import React, { useState, useMemo } from 'react';

const ITEMS = ['bread', 'milk', 'diaper', 'beer', 'cola', 'eggs'];
const COLORS = {
  bread: '#fbbf24', milk: '#38bdf8', diaper: '#a3e635',
  beer: '#fb923c', cola: '#f472b6', eggs: '#a78bfa'
};
const LABELS = {
  bread: 'Bread', milk: 'Milk', diaper: 'Diaper',
  beer: 'Beer', cola: 'Cola', eggs: 'Eggs'
};
const TXS = [
  ['bread', 'milk'],
  ['bread', 'diaper', 'beer', 'eggs'],
  ['milk', 'diaper', 'beer', 'cola'],
  ['bread', 'milk', 'diaper', 'beer'],
  ['bread', 'milk', 'diaper', 'cola'],
];

function getCombos(arr, k) {
  if (k === 1) return arr.map(x => [x]);
  const r = [];
  for (let i = 0; i <= arr.length - k; i++) {
    getCombos(arr.slice(i + 1), k - 1).forEach(c => r.push([arr[i], ...c]));
  }
  return r;
}

export default function App() {
  const [minSupport, setMinSupport] = useState(0.6);
  const [selected, setSelected] = useState(null);
  const n = TXS.length;

  const result = useMemo(() => {
    const minCount = minSupport * n;
    const levels = [];
    let totalPruned = 0;
    let totalChecked = 0;

    const l1 = ITEMS.map(item => {
      const count = TXS.filter(t => t.includes(item)).length;
      totalChecked++;
      return { items: [item], count, support: count / n, frequent: count >= minCount };
    });
    levels.push({ k: 1, itemsets: l1, pruned: 0 });

    let prevFreq = l1.filter(x => x.frequent).map(x => x.items);

    for (let k = 2; k <= 4; k++) {
      const allCombos = getCombos(ITEMS, k);
      const pSet = new Set(prevFreq.map(x => JSON.stringify(x)));
      let pruned = 0;
      const candidates = [];

      allCombos.forEach(items => {
        const subs = getCombos(items, k - 1);
        if (!subs.every(s => pSet.has(JSON.stringify(s)))) {
          pruned++;
          return;
        }
        const count = TXS.filter(t => items.every(i => t.includes(i))).length;
        totalChecked++;
        candidates.push({ items, count, support: count / n, frequent: count >= minCount });
      });

      totalPruned += pruned;
      if (candidates.length === 0 && pruned === 0) break;
      levels.push({ k, itemsets: candidates, pruned });
      prevFreq = candidates.filter(x => x.frequent).map(x => x.items);
      if (prevFreq.length === 0 && k >= 2) {
        const nextCombos = getCombos(ITEMS, k + 1);
        if (nextCombos.length > 0) totalPruned += nextCombos.length;
        break;
      }
    }

    const totalPossible = [6, 15, 20, 15].reduce((s, v) => s + v, 0);
    return { levels, totalPruned, totalChecked, totalPossible };
  }, [minSupport]);

  const hlTxs = useMemo(() => {
    if (!selected) return new Set();
    return new Set(TXS.map((t, i) => selected.every(item => t.includes(item)) ? i : -1).filter(i => i >= 0));
  }, [selected]);

  const totalFrequent = result.levels.reduce((s, l) => s + l.itemsets.filter(x => x.frequent).length, 0);

  const getInsight = () => {
    if (minSupport <= 0.2) return "At very low support, almost everything is frequent - too many patterns to be useful. This is why choosing the right threshold matters!";
    if (minSupport <= 0.4) return "Lower support reveals more patterns including beer and cola combinations. But some may be coincidental - appearing in just 1-2 transactions.";
    if (minSupport <= 0.6) return "At 60% support, we find the core shopping patterns: bread-milk, bread-diaper, and milk-diaper are commonly bought together.";
    if (minSupport <= 0.8) return "At high support, only the most common individual items survive. Pair patterns are eliminated - the threshold is too strict for combinations.";
    return "At 100% support, an item must appear in EVERY transaction. Almost nothing qualifies - the threshold is too restrictive.";
  };

  const ItemPill = ({ item, small }) => (
    <span style={{
      display: 'inline-flex', alignItems: 'center', gap: 4,
      background: COLORS[item] + '20', border: '1px solid ' + COLORS[item] + '60',
      borderRadius: 4, padding: small ? '1px 5px' : '2px 6px',
      fontSize: small ? 10 : 11, color: COLORS[item], fontWeight: 600,
      whiteSpace: 'nowrap'
    }}>
      {LABELS[item]}
    </span>
  );

  const ItemsetCard = ({ itemset }) => {
    const { items, support, frequent, count } = itemset;
    const isSelected = selected && JSON.stringify(selected) === JSON.stringify(items);
    return (
      <div
        onClick={() => setSelected(isSelected ? null : items)}
        style={{
          background: isSelected ? '#1e293b' : frequent ? '#111827' : '#0d0d12',
          border: '1px solid ' + (isSelected ? '#3b82f6' : frequent ? '#1e293b' : '#1a1a22'),
          borderRadius: 8, padding: '6px 10px', cursor: 'pointer',
          opacity: frequent ? 1 : 0.45,
          transition: 'all 0.25s ease',
          minWidth: 70,
        }}
      >
        <div style={{ display: 'flex', gap: 3, marginBottom: 5, flexWrap: 'wrap' }}>
          {items.map(item => <ItemPill key={item} item={item} small />)}
        </div>
        <div style={{ position: 'relative', height: 14, background: '#1a1a2e', borderRadius: 3, overflow: 'hidden' }}>
          <div style={{
            position: 'absolute', left: 0, top: 0, bottom: 0,
            width: (support * 100) + '%',
            background: frequent ? 'linear-gradient(90deg, #3b82f6, #60a5fa)' : '#333',
            borderRadius: 3, transition: 'width 0.3s ease'
          }} />
          <div style={{
            position: 'absolute', left: 0, top: 0, bottom: 0, width: '100%',
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 9, fontWeight: 700, color: '#e2e8f0',
            fontFamily: 'monospace', textShadow: '0 1px 2px rgba(0,0,0,0.8)'
          }}>
            {(support * 100).toFixed(0)}% ({count}/{n})
          </div>
        </div>
      </div>
    );
  };

  const thresholdPercent = (minSupport * 100).toFixed(0);

  return (
    <div style={{ background: '#0a0a0f', minHeight: '100vh', display: 'flex', justifyContent: 'center', padding: '12px 16px', fontFamily: "'Inter', system-ui, sans-serif" }}>
      <div style={{ maxWidth: 600, width: '100%' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
          <h1 style={{ color: '#f1f5f9', fontSize: 17, fontWeight: 700, margin: 0 }}>Apriori Frequent Itemset Mining</h1>
          <div style={{ display: 'flex', gap: 4 }}>
            {[0.2, 0.4, 0.6, 0.8].map(v => (
              <button key={v} onClick={() => setMinSupport(v)} style={{
                background: Math.abs(minSupport - v) < 0.01 ? '#3b82f6' : '#1e293b',
                color: Math.abs(minSupport - v) < 0.01 ? '#fff' : '#94a3b8',
                border: 'none', borderRadius: 4, padding: '3px 8px',
                fontSize: 11, cursor: 'pointer', fontWeight: 600
              }}>{(v * 100).toFixed(0)}%</button>
            ))}
          </div>
        </div>

        {/* Transactions Matrix */}
        <div style={{ background: '#111118', borderRadius: 10, padding: '8px 10px', marginBottom: 10, border: '1px solid #1e1e2e' }}>
          <div style={{ fontSize: 10, color: '#64748b', marginBottom: 6, fontWeight: 600, textTransform: 'uppercase', letterSpacing: 1 }}>5 Transactions (click an itemset below to highlight)</div>
          <div style={{ display: 'grid', gridTemplateColumns: '28px repeat(6, 1fr)', gap: '2px 4px', alignItems: 'center' }}>
            <div />
            {ITEMS.map(item => (
              <div key={item} style={{ textAlign: 'center', fontSize: 9, color: COLORS[item], fontWeight: 700, opacity: 0.8 }}>
                {LABELS[item].slice(0, 3)}
              </div>
            ))}
            {TXS.map((tx, ti) => (
              <React.Fragment key={ti}>
                <div style={{
                  fontSize: 10, color: hlTxs.has(ti) ? '#f1f5f9' : '#52525b',
                  fontWeight: 700, fontFamily: 'monospace',
                  transition: 'color 0.2s'
                }}>T{ti + 1}</div>
                {ITEMS.map(item => {
                  const has = tx.includes(item);
                  const hl = hlTxs.has(ti) && selected && selected.includes(item);
                  return (
                    <div key={item} style={{
                      textAlign: 'center', height: 20,
                      display: 'flex', alignItems: 'center', justifyContent: 'center',
                      borderRadius: 3,
                      background: hl ? COLORS[item] + '30' : 'transparent',
                      transition: 'all 0.2s'
                    }}>
                      {has ? (
                        <div style={{
                          width: 12, height: 12, borderRadius: 3,
                          background: hlTxs.size > 0 ? (hlTxs.has(ti) ? COLORS[item] : COLORS[item] + '20') : COLORS[item] + '80',
                          transition: 'all 0.25s',
                          boxShadow: hl ? '0 0 6px ' + COLORS[item] + '60' : 'none'
                        }} />
                      ) : (
                        <div style={{ width: 12, height: 12, borderRadius: 3, border: '1px solid #1a1a2e' }} />
                      )}
                    </div>
                  );
                })}
              </React.Fragment>
            ))}
          </div>
        </div>

        {/* Support Slider */}
        <div style={{
          background: '#111118', borderRadius: 10, padding: '10px 14px', marginBottom: 10,
          border: '1px solid #1e1e2e', display: 'flex', alignItems: 'center', gap: 12
        }}>
          <div style={{ fontSize: 11, color: '#94a3b8', fontWeight: 600, whiteSpace: 'nowrap' }}>Min Support</div>
          <input
            type="range" min={0.2} max={1.0} step={0.05}
            value={minSupport}
            onChange={e => { setMinSupport(parseFloat(e.target.value)); setSelected(null); }}
            style={{ flex: 1, accentColor: '#3b82f6', height: 4, cursor: 'pointer' }}
          />
          <div style={{
            fontSize: 16, fontWeight: 800, color: '#3b82f6', fontFamily: 'monospace',
            minWidth: 44, textAlign: 'right'
          }}>{thresholdPercent}%</div>
          <div style={{
            background: totalFrequent > 0 ? '#10b981' + '25' : '#f43f5e25',
            color: totalFrequent > 0 ? '#10b981' : '#f43f5e',
            borderRadius: 12, padding: '2px 8px', fontSize: 11, fontWeight: 700
          }}>{totalFrequent} found</div>
        </div>

        {/* Results Levels */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8, marginBottom: 10 }}>
          {result.levels.map(level => (
            <div key={level.k} style={{
              background: '#111118', borderRadius: 10, padding: '8px 10px',
              border: '1px solid #1e1e2e'
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: level.itemsets.length > 0 ? 6 : 0 }}>
                <span style={{
                  fontSize: 11, fontWeight: 700, color: '#8b5cf6', fontFamily: 'monospace',
                  background: '#8b5cf620', borderRadius: 4, padding: '1px 6px'
                }}>k={level.k}</span>
                <span style={{ fontSize: 10, color: '#64748b' }}>
                  {level.itemsets.filter(x => x.frequent).length} frequent
                  {level.itemsets.filter(x => !x.frequent).length > 0 ? ', ' + level.itemsets.filter(x => !x.frequent).length + ' below threshold' : ''}
                </span>
                {level.pruned > 0 && (
                  <span style={{
                    fontSize: 10, color: '#f59e0b', fontWeight: 600,
                    background: '#f59e0b15', borderRadius: 4, padding: '1px 6px', marginLeft: 'auto'
                  }}>
                    {level.pruned} pruned
                  </span>
                )}
              </div>
              {level.itemsets.length > 0 && (
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 5 }}>
                  {[...level.itemsets].sort((a, b) => b.support - a.support).map((is, i) => (
                    <ItemsetCard key={i} itemset={is} />
                  ))}
                </div>
              )}
              {level.itemsets.length === 0 && (
                <div style={{ fontSize: 10, color: '#52525b', fontStyle: 'italic', padding: '2px 0' }}>All candidates pruned by anti-monotonicity</div>
              )}
            </div>
          ))}
        </div>

        {/* Efficiency Insight */}
        <div style={{
          background: '#111118', borderRadius: 10, padding: '10px 14px',
          border: '1px solid #1e1e2e', marginBottom: 8
        }}>
          <div style={{ display: 'flex', gap: 16, marginBottom: 8 }}>
            <div style={{ flex: 1, textAlign: 'center' }}>
              <div style={{ fontSize: 20, fontWeight: 800, color: '#3b82f6', fontFamily: 'monospace' }}>{result.totalChecked}</div>
              <div style={{ fontSize: 9, color: '#64748b', fontWeight: 600 }}>Apriori checked</div>
            </div>
            <div style={{ flex: 1, textAlign: 'center' }}>
              <div style={{ fontSize: 20, fontWeight: 800, color: '#f43f5e', fontFamily: 'monospace' }}>{result.totalPossible}</div>
              <div style={{ fontSize: 9, color: '#64748b', fontWeight: 600 }}>Brute force would check</div>
            </div>
            <div style={{ flex: 1, textAlign: 'center' }}>
              <div style={{ fontSize: 20, fontWeight: 800, color: '#f59e0b', fontFamily: 'monospace' }}>{result.totalPruned}</div>
              <div style={{ fontSize: 9, color: '#64748b', fontWeight: 600 }}>Pruned (anti-monotonicity)</div>
            </div>
          </div>
          <div style={{
            fontSize: 11, color: '#94a3b8', lineHeight: 1.6,
            borderLeft: '3px solid #3b82f6', paddingLeft: 10
          }}>
            {getInsight()}
            {result.totalPruned > 0 && (
              <span style={{ color: '#f59e0b' }}> Anti-monotonicity saved {((result.totalPruned / result.totalPossible) * 100).toFixed(0)}% of work: if an item like eggs is infrequent, ALL supersets containing it are skipped.</span>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

